            buffer_ptr[i] = buffer_list[i];
        }

        static constexpr int kElemsPerThread = kAtoms * kElemsPerAtom;
        static constexpr int kRowsPerTile    = kTileSize / (hidden_dim * sizeof(T));
        static_assert(kTileSize % (hidden_dim * sizeof(T)) == 0,
                      "hidden_dim * sizeof(T) must divide kTileSize");

        __shared__ float s_row_sq_sum[kRowsPerTile];

        int32x4_t tA[kAtoms];

        BufferResource src_buffer(const_cast<T*>(input), N * sizeof(T));
        uint32_t src_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            tA[i] = buffer_load_dwordx4(src_buffer.descriptor, src_offset, 0, 0);
            src_offset += kAtomStride * sizeof(int32x4_t);
            if constexpr(cast_bf2half)
            {
                const nv_bfloat162* bf_buf = reinterpret_cast<const nv_bfloat162*>(&tA[i]);
                half2 half_buf[4];
#pragma unroll
                for(int j = 0; j < 4; ++j)
                {
                    float2 f    = __bfloat1622float2(bf_buf[j]);
                    half_buf[j] = __float22half2_rn(f);
                }
                tA[i] = *reinterpret_cast<const int32x4_t*>(half_buf);
            }
        }

        uint32_t comm_data0_offset = data_offset + block_id * Codec::kTransmittedTileSize;
        uint32_t comm_data1_offset = data_size_per_phase + comm_data0_offset;

        uint32_t comm_flags0_offset = block_id * (kWorldSize * sizeof(uint32_t));
        uint32_t comm_flags1_offset = (data_offset / 2) + comm_flags0_offset;

        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data0_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, &tA[r * Codec::kRankAtoms]);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags0_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        int32x4_t tR[Codec::kRankAtoms] = {};
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data0_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags0_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, tA);

                for(int i = 0; i < Codec::kRankAtoms; i++)
                {
                    packed_assign_add<T>(&tR[i], &tA[i]);
                }
            }
        }

        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data1_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, tR);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags1_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data1_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags1_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, &tA[r * Codec::kRankAtoms]);
            }
        }

        T residual_local[kElemsPerThread];
        T reduced_val[kElemsPerThread];
        float x_f32[kElemsPerThread];

        for(int i = 0; i < kAtoms; i++)
        {
            T* elem_ptr = reinterpret_cast<T*>(&tA[i]);
            for(int j = 0; j < kElemsPerAtom; j++)
            {
                reduced_val[i * kElemsPerAtom + j] = elem_ptr[j];
            }
        }

        BufferResource residual_inp_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
        uint32_t residual_offset = block * kTileSize + thread * sizeof(int32x4_t);
        int32x4_t tRes[kAtoms];
        for(int i = 0; i < kAtoms; i++)
        {
            tRes[i] = buffer_load_dwordx4(residual_inp_buffer.descriptor, residual_offset, 0, 0);
            residual_offset += kAtomStride * sizeof(int32x4_t);
        }
        for(int i = 0; i < kAtoms; i++)
        {
            T* elem_ptr = reinterpret_cast<T*>(&tRes[i]);
            for(int j = 0; j < kElemsPerAtom; j++)
            {
                residual_local[i * kElemsPerAtom + j] = elem_ptr[j];
            }
        }

        float row_sq_sum[kRowsPerTile] = {0.0f};

        for(int elem = 0; elem < kElemsPerThread; elem++)
        {
            float r_f32 = qr_to_float(reduced_val[elem]);
            float res_f32 = qr_to_float(residual_local[elem]);
            float x = r_f32 + res_f32;
            x_f32[elem] = x;
            residual_local[elem] = qr_from_float<T>(x);

            int row = elem / hidden_dim;
            row_sq_sum[row] += x * x;
        }

        for(int row = 0; row < kRowsPerTile; row++)
        {
            float sum = row_sq_sum[row];
            for(int offset = kWavefront / 2; offset > 0; offset >>= 1)
            {
                sum += __shfl_down(sum, offset);
            }
            if(threadIdx.x % kWavefront == 0)
            {
                s_row_sq_sum[row] = sum;
            }
        }

        __syncthreads();

        float row_mean[kRowsPerTile];
        float row_denom[kRowsPerTile];
        if(threadIdx.x < kRowsPerTile)
        {
            row_mean[threadIdx.x] = s_row_sq_sum[threadIdx.x] / hidden_dim;
            row_denom[threadIdx.x] = rsqrtf(row_mean[threadIdx.x] + eps);
        }
        __syncthreads();

        T weight_local[kElemsPerThread];
        BufferResource weight_buffer(const_cast<T*>(weight), hidden_dim * sizeof(T));
        uint32_t weight_offset = thread * sizeof(int32x4_t);
        int32x4_t tW[kAtoms];
        for(int i = 0; i < kAtoms; i++)
        {
            if(thread * sizeof(int32x4_t) + i * kAtomStride * sizeof(int32x4_t) < hidden_dim * sizeof(T))
            {
                tW[i] = buffer_load_dwordx4(weight_buffer.descriptor, weight_offset, 0, 0);
            }
            else
            {
                tW[i] = make_int32x4(0, 0, 0, 0);
            }
            weight_offset += kAtomStride * sizeof(int32x4_t);
        }
        for(int i = 0; i < kAtoms; i++)
        {
            T* elem_ptr = reinterpret_cast<T*>(&tW[i]);
            for(int j = 0; j < kElemsPerAtom; j++)
            {
                weight_local[i * kElemsPerAtom + j] = elem_ptr[j];
            }
        }

        for(int elem = 0; elem < kElemsPerThread; elem++)
        {
            int row = elem / hidden_dim;
            int col = elem % hidden_dim;
            float x = x_f32[elem];
            float w = qr_to_float(weight_local[elem]);
            float denom = row_denom[row];
            float out_val = x * denom * w;
            residual_local[elem] = qr_from_float<T>(x);

            BufferResource out_buffer(output, N * sizeof(T));
            BufferResource res_out_buffer(residual_out, N * sizeof(T));
            uint32_t base_offset = block * kTileSize + (thread * kElemsPerThread + elem) * sizeof(T);

            if(base_offset < N * sizeof(T))
            {
                T out_t = qr_from_float<T>(out_val);
                if(sizeof(T) == 2)
                {
                    uint32_t val = *reinterpret_cast<uint32_t*>(&out_t);
                    int32x4_t store_val = make_int32x4(val, 0, 0, 0);
                    buffer_store_dwordx4(store_val, out_buffer.descriptor, base_offset, 0, 0);

                    T res_t = residual_local[elem];
                    val = *reinterpret_cast<uint32_t*>(&res_t);
                    store_val = make_int32x4(val, 0, 0, 0);
                    buffer_store_dwordx4(store_val, res_out_buffer.descriptor, base_offset, 0, 0);
                }
            }
        }
    }

